一、背景介绍ThreadLocal是线程提供的本地变量，因其线程特殊属性，被经常用于存储与线程相关的信息，如保存登录用户信息、数据库连接配置等。但我们忽略了一个关键点：ThreadLocal 只能用在同步线程中，而在异步线程或线程池中则不起作用。因此，本博文主要探讨如何在异步线程和线程池中传递 ThreadLocal 上下文。
二、问题描述发版之后，爆出线上问题：“用户信息获取失败”。为了更好地解释这个问题，先介绍下公司的系统架构：用户登录时，后台系统通过用户 key 获取个人信息并保存在 ThreadLocal 静态对象中，以供后续使用。简要实现如下：
/*** 拦截器*/@Componentpublic class HandlerAccessInterceptor implements HandlerInterceptor &#123;        @Override    public boolean preHandle(HttpServletRequest httpServletRequest,                             HttpServletResponse httpServletResponse, Object o) throws Exception &#123;        // 增加允许跨域的返回信息        httpServletResponse.setHeader("Access-Control-Allow-Origin", "*");        httpServletResponse.setHeader("Access-Control-Allow-Headers", "Content-Type,Content-Length, Authorization, Accept,X-Requested-With");        httpServletResponse.setHeader("Access-Control-Allow-Methods", "PUT,POST,GET,DELETE,OPTIONS");                // 获取并保存用户信息        if (httpServletRequest.getCookies() != null) &#123;            for (Cookie cookie : httpServletRequest.getCookies()) &#123;                if ("vkey".equals(cookie.getName())) &#123;                    UserContextUtil.setUser(cookie.getValue());                &#125;            &#125;        &#125;                return true;    &#125;        @Override    public void postHandle(HttpServletRequest httpServletRequest, HttpServletResponse httpServletResponse, Object o, ModelAndView modelAndView) throws Exception &#123;    &#125;        // 清除用户信息    @Override    public void afterCompletion(HttpServletRequest httpServletRequest, HttpServletResponse httpServletResponse, Object o, Exception e) throws Exception &#123;        UserContextUtil.remove();    &#125;&#125;/*** 用户信息工具*/@Componentpublic class UserContextUtil &#123;    private static ThreadLocal&lt;SyUser&gt; threadLocal = new ThreadLocal&lt;&gt;();    private static final String TOKEN_BEARER = "Bearer ";    /**     * 获取当前线程用户信息     *     * @return 前线程用户信息     */    public synchronized static SyUser getUser() &#123;        SyUser syUser = threadLocal.get();        return syUser;    &#125;    /**    * 直接保存用户信息    */    public synchronized static boolean setSyUser(SyUser syUser) &#123;        if (syUser == null) &#123;            return false;        &#125;        threadLocal.set(syUser);        return true;    &#125;    /**     * 转换登录用户信息为当期系统用户信息     *     * @param cookies     */    public synchronized static boolean setUser(Cookie[] cookies) &#123;        if (cookies == null) &#123;            return false;        &#125;        for (Cookie cookie : cookies) &#123;            String name = cookie.getName().toLowerCase();            if ("vkey".equals(name)) &#123;                String value = cookie.getValue();                if (StrUtil.isEmpty(value)) &#123;                    return false;                &#125;                LoginUser loginUser = new LoginUser(value);                if (loginUser.getId() == null) &#123;                    return false;                &#125;                SyUser syUser = new SyUser();                syUser.setId(loginUser.getId().intValue());                syUser.setUserName(loginUser.getMobile());                syUser.setTrueName(loginUser.getName());                return setSyUser(syUser);            &#125;        &#125;        return false;    &#125;    /**     * 转换登录用户信息为当期系统用户信息     *     * @param headerValue 头部 vkey 值     */    public synchronized static boolean setUser(String headerValue) &#123;        if (StrUtil.isEmpty(headerValue)) &#123;            return false;        &#125;        if (headerValue.startsWith(TOKEN_BEARER)) &#123;            headerValue = headerValue.substring(TOKEN_BEARER.length());        &#125;        LoginUser loginUser = new LoginUser(headerValue);        if (loginUser.getId() == null) &#123;            return false;        &#125;        SyUser syUser = new SyUser();        syUser.setId(loginUser.getId().intValue());        syUser.setUserName(loginUser.getMobile());        syUser.setTrueName(loginUser.getName());        syUser.setPhone(loginUser.getMobile());        return setSyUser(syUser);    &#125;        /**     * 获取登录用户姓名     */    public synchronized static String getUserName() &#123;        SyUser syUser = threadLocal.get();        if (syUser == null) &#123;            return null;        &#125;        return syUser.getTrueName();    &#125;    /**     * 移除线程中用户信息     */    public synchronized static void remove() &#123;        threadLocal.remove();    &#125;&#125;
问题代码定位：
@RestController@RequestMapping("/web/file")@Slf4jpublic class ManageFileController &#123;        @Resource    private ManageFileService manageFileService;    	/**     * 【加载文件】     * 下载文件的数据准备阶段可能非常长, 前台操作人员无法得知进度, 且无法做其他操作     * 故将数据准备与文件下载解耦, 解决交互上不舒服的问题     *     * @param loadFileReqDTO 加载文件请求     * @return 调用是否成功     */    @PostMapping("/loadFile")    public RespDTO&lt;String&gt; loadFile(@Valid @RequestBody LoadFileReqDTO loadFileReqDTO) &#123;        // 初始化加载文件信息        AsyncLoadFile asyncLoadFile = manageFileService.initLoadFileInfo(loadFileReqDTO);        // 执行文件加载        manageFileService manageFileService.loadFile(loadFileReqDTO, inheritedSyUser);        return RespDTO.success();    &#125;&#125;/** * @author zourongsheng * @version 1.0 * @date 2020/10/21 13:55 */@Service@Slf4jpublic class ManageFileService &#123;        @Resource    private ManageFileHelper manageFileHelper;        @Resource    private AsyncLoadFileMapper asyncLoadFileMapper;        /**     * 【加载文件】     *     * @param loadFileReqDTO 加载文件请求     * @param asyncLoadFile  初始化加载文件信息     * @param syUser         用户信息     */    @Async(TASK_EXECUTOR)    public void loadFile(LoadFileReqDTO loadFileReqDTO, AsyncLoadFile asyncLoadFile, SyUser syUser) &#123;        try &#123;            log.info("异步加载文件开始; userName: &#123;&#125;", UserContextUtil.getUserName());            // 路由加载服务            LoadFileService loadFileService = manageFileHelper.router(loadFileReqDTO.getLoadFileType());            // 开启文件加载过程            LoadFileReqBO loadFileReqBO = new LoadFileReqBO();            BeanUtils.copyProperties(loadFileReqDTO, loadFileReqBO);            LoadFileRespBO loadFileRespBO = loadFileService.executeLoadFile(loadFileReqBO);            // 备份文件至影像件系统            String fileKey = FileUtil.uploadFile(loadFileRespBO.getFilePathUrl(), FileTypeEnum.XLSX, STORE_FILE_KEY);            CuiShouAssert.notEmpty(fileKey, "调用影像件系统异常!");            asyncLoadFile.setFileName(loadFileRespBO.getFileName());            asyncLoadFile.setFileKey(fileKey);            asyncLoadFile.setLoadStatus(LoadStatusEnum.SUCCESS.name());        &#125; catch (Exception e) &#123;            log.info("加载文件异常; errMsg: &#123;&#125;", e.getMessage(), e);            asyncLoadFile.setLoadStatus(LoadStatusEnum.FAILURE.name());            asyncLoadFile.setRemark(e.getMessage());        &#125;        asyncLoadFileMapper.update(asyncLoadFile);                log.info("异步加载文件结束; userName: &#123;&#125;", UserContextUtil.getUserName());    &#125;&#125;
运行结果...2020-12-14 17:51:15.235  INFO [-,d11235d6f6eda8d0,8c023b1e45855f97,false] 19444 --- [common-async-executor-1] c.v.c.o.service.file.ManageFileService   : 异步加载文件开始; userName: null
问题很好定位，@Async 异步线程池开启子线程处理任务后，父线程提供的本地线程变量就销毁了。
三、解决方法
将用户信息当作参数传入异步方法，再在异步方法中重新设置本地变量；
采用 InheritedThreadLocal 实现子线程上下文的传递。

/** * 【加载文件-方法一】 * 下载文件的数据准备阶段可能非常长, 前台操作人员无法得知进度, 且无法做其他操作 * 故将数据准备与文件下载解耦, 解决交互上不舒服的问题 * * @param loadFileReqDTO 加载文件请求 * @return 调用是否成功 */@PostMapping("/loadFile")public RespDTO&lt;String&gt; loadFile(@Valid @RequestBody LoadFileReqDTO loadFileReqDTO) &#123;    // 初始化加载文件信息    AsyncLoadFile asyncLoadFile = manageFileService.initLoadFileInfo(loadFileReqDTO);        // #loadFile 为异步方法, 这里将操作人信息继承到子线程中    SyUser syUser = UserContextUtil.getUser();    SyUser inheritedSyUser = new SyUser();    BeanUtils.copyProperties(syUser, inheritedSyUser);    // 执行文件加载    manageFileService manageFileService.loadFile(loadFileReqDTO, inheritedSyUser);    return RespDTO.success();&#125;/*** 【加载文件】* 下载文件的数据准备阶段可能非常长, 前台操作人员无法得知进度, 且无法做其他操作* 故将数据准备与文件下载解耦, 解决交互上不舒服的问题** @param loadFileReqDTO 加载文件请求* @param asyncLoadFile  初始化加载文件信息* @param syUser         用户信息*/@Async(TASK_EXECUTOR)public void loadFile(LoadFileReqDTO loadFileReqDTO, AsyncLoadFile asyncLoadFile, SyUser syUser) &#123;        UserContextUtil.setSyUser(syUser);    log.info("异步加载文件开始; UserName: &#123;&#125;", UserContextUtil.getRealName());    UserContextUtil.remove();    log.info("异步加载文件结束; UserName: &#123;&#125;", UserContextUtil.getRealName());&#125;
方法一运行结果...2020-12-14 18:03:34.947  INFO [-,480f9c55e785ec6f,c8de532979871193,false] 19444 --- [common-async-executor-2] c.v.c.o.service.file.ManageFileService   : 异步加载文件开始; UserName: 邹荣升2020-12-14 18:03:35.235  INFO [-,480f9c55e785ec6f,c8de532979871193,false] 19444 --- [common-async-executor-2] c.v.c.o.service.file.ManageFileService   : 异步加载文件结束; UserName: null
方法一可以说是傻瓜操作，治标不治本，后来的同事稍不注意还会掉进坑里。我们来实现方法二：
private static ThreadLocal&lt;SyUser&gt; threadLocal = new InheritableThreadLocal&lt;&gt;();/*** 【加载文件-异步线程】* 下载文件的数据准备阶段可能非常长, 前台操作人员无法得知进度, 且无法做其他操作* 故将数据准备与文件下载解耦, 解决交互上不舒服的问题** @param loadFileReqDTO 加载文件请求* @param asyncLoadFile  初始化加载文件信息* @param syUser         用户信息*/@Asyncpublic void loadFile(LoadFileReqDTO loadFileReqDTO, AsyncLoadFile asyncLoadFile, SyUser syUser) &#123;        UserContextUtil.setSyUser(syUser);    log.info("异步加载文件开始; UserName: &#123;&#125;", UserContextUtil.getRealName());    UserContextUtil.remove();    log.info("异步加载文件结束; UserName: &#123;&#125;", UserContextUtil.getRealName());&#125;/*** 【加载文件-异步线程池】* 下载文件的数据准备阶段可能非常长, 前台操作人员无法得知进度, 且无法做其他操作* 故将数据准备与文件下载解耦, 解决交互上不舒服的问题** @param loadFileReqDTO 加载文件请求* @param asyncLoadFile  初始化加载文件信息* @param syUser         用户信息*/@Async(TASK_EXECUTOR)public void loadFile(LoadFileReqDTO loadFileReqDTO, AsyncLoadFile asyncLoadFile, SyUser syUser) &#123;        UserContextUtil.setSyUser(syUser);    log.info("异步加载文件开始; UserName: &#123;&#125;", UserContextUtil.getRealName());    UserContextUtil.remove();    log.info("异步加载文件结束; UserName: &#123;&#125;", UserContextUtil.getRealName());&#125;
异步线程和异步线程池两种情况下的运行结果：
运行结果...2020-12-14 18:36:41.560  INFO [-,8658c694de3e9b7a,ccc7a782204c91b0,false] 19876 --- [common-async-executor-1] c.v.c.o.service.file.ManageFileService   : 异步加载文件开始; UserName: 邹荣升2020-12-14 18:41:17.735  INFO [-,67b4725bcaacfc64,36ee2acec232be32,false] 21600 --- [common-async-executor-1] c.v.c.o.service.file.ManageFileService   : 异步加载文件开始; UserName: 邹荣升
三、总结虽然 ThreadLocal 的线程相关属性提供了很多便利性，但在高并发系统中，直接使用原生静态对象并不合适。因此，如使用 Redis、MQ 一样，深入了解常用工具的特性，是系统设计的必备要素。

一、背景介绍Axios 是一个基于 Promise 的 HTTP 库，可以用在浏览器和 node.js 中。与传统的 Ajax 相比，Axios 的优势主要体现在: 支持 Promise API 、支持并发、支持请求与响应拦截、自动转换 JSON 数据、支持防御 XSRF、符合 MVVM 设计理念。在目前大火的前端框架 Vue 中也内置了 Axios 框架 。

正是因为 Axios 的数据处理为 json 格式，所以只能获取文件流，但不能给与正确处理。具体表现为:

response.status 与 repsponse.headers 与期望相同，但 response.data 为一团乱码
浏览器没有自动下载文件 


二、引入 Blob  容器实现文件下载既然 Axios 无法正确处理文件流，便需要采用其他技术来达到预期效果。Blob 对象表示一个不可变、原始数据的类文件对象；从字面意思来看，Blob 也是一个可以存储二进制文件的容器。通过这项技术，可以完美地弥补 Axios 的不足。具体实现如下:
// 下载文件请求export function download (param) &#123;  return axios(&#123;    url: '/web/bill/download',    method: 'post',    data: param,    responseType: 'blob'  &#125;)&#125;// 下载文件入口方法download(this.param).then(response =&gt; &#123;    // 执行文件下载    this.exeDownloadFile(response)&#125;)// 执行文件下载exeDownloadFile (response) &#123;    // 创建 Blob 对象    let blob = new Blob([response.data], &#123;type: response.headers['content-type']&#125;)    // 获取文件名    let fileName = response.headers['content-disposition'].match(/filename=(.*)/)[1]    // 创建指向 Blob 对象地址的URL    let href = window.URL.createObjectURL(blob)    // 创建用于跳转至下载链接的 a 标签    let downloadElement = document.createElement('a')    // 属性配置    downloadElement.style.display = 'none'    downloadElement.href = href    downloadElement.download = fileName    // 将 a 标签挂载至当前页面    document.body.appendChild(downloadElement)    // 触发下载事件    downloadElement.click()    // 移除已挂载的 a 标签    document.body.removeChild(downloadElement)    // 释放 Blob URL    window.URL.revokeObjectURL(href)&#125;
虽然以上可以实现文件下载，但美中不足的是，当后台返回异常时，通过 Blob 对象依然可以下载到一个 undefined 文件。因此，在执行下载之前，需要对下载请求是否存在异常做出判断。具体实现如下:
// 下载文件入口方法download(this.param).then(response =&gt; &#123;    let fr = new FileReader()    fr.readAsText(response.data)    fr.onload = function () &#123;        // 新增-异常校验; 若 Blob 对象可 JSON 格式化，则说明文件下载异常    	try &#123;    	    let jsonRet = JSON.parse(this.result)    	&#125; catch (e) &#123;    	    // 执行文件下载            this.exeDownloadFile(response)    	&#125;    &#125;&#125;)

一、需求背景本周负责做调账线上化，其中一个业务需求比较棘手：提交调账申请后，需在数据表记录对应的调账类型；而在调账复核页面，列表筛选项-调账类型，需支持多选。简单枚举如下:
public enum AdjustTypeEnum &#123;    /**     * 调账类型枚举; 一次调账申请可能对应多种调账类型，在数据表中枚举值之间以英文 , 分隔     */    FINE(0, "应还罚息"),    TOTAL_REPAYMENT(1, "应还总额"),    FACT_REPAYMENT(2, "实还总额"),    FACT_PAYMENT_DATE(3, "实还日期"),    OVERDUE_DAYS(4, "逾期天数"),    PAYMENT_STATUS(5, "还款状态");&#125;
假如调账申请A的调账类型包括应还罚息和应还总额，则数据表相应字段值为0,1。在复核页面，若调账类型复选项中包含应还罚息或应还总额，则需查询到该申请。此时，我们发现SQL内置函数FIND_IN_SET只支持单选项查询，而无法灵活拆分筛选条件和存储数据。因此，有必要调整一下数据的存储规则和查询规则。
二、位与运算的妙用首先，我们需要进一步抽象：一方面，为了不浪费存储空间，科学地设计数据表，我们需要将目标数据列表整合存储在一个字段中；另一方面，数据库引擎需要灵活使用整合后的字段，以执行相应的查询语句。说白了，就是看起来像做了整合，实际上还是原始的目标数据列表。
事实证明，上面提出的方案根本满足不了业务需求，是一个非常差的设计。除了以逗号分隔枚举值的存储方式，还有一种更为科学的存储方式——二进制。简单做几个位与运算：
// 存储值: 3; 查询条件: 1// 3 == 2 + 1// 1 &amp; 3 == 10001&amp;0011=0001
// 存储值: 7; 查询条件: 1// 7 == 1 + 2 + 4// 1 &amp; 7 == 10111&amp;0001=0001
// 存储值: 7; 查询条件: 3// 7 == 1 + 2 + 4// 3 == 1 + 2// 3 &amp; 7 == 30111&amp;0011=0011
// 存储值: 7; 查询条件: 15// 7 == 1 + 2 + 4// 15 == 1 + 2 + 4 + 8// 15 &amp; 7 == 70111&amp;1111=0111
从以上位与运算实例，可以发现一个有趣的现象：若将枚举值设置为2的n次幂，则只需将目标数据列表加合，即可保证每一个目标数据对应到二进制中的一位。

此时，对于任何一个查询条件，只需要将其与整合值进行位与运算，即可得到匹配的值。
由此，我们调整枚举为：
public enum AdjustTypeEnum &#123;    /**     * 调账类型枚举; 一次调账申请可能对应多种调账类型，在数据表中存储各值之和     */    FINE(1, "应还罚息"),    TOTAL_REPAYMENT(2, "应还总额"),    FACT_REPAYMENT(4, "实还总额"),    FACT_PAYMENT_DATE(8, "实还日期"),    OVERDUE_DAYS(16, "逾期天数"),    PAYMENT_STATUS(32, "还款状态");&#125;
调整SQL为：
SELECT*FROM `boss-account`.acct_adjust_account_recordWHEREadjust_type_sum &amp; #&#123;调账类型筛选条件值之和&#125; &gt; 0

一、背景介绍HTTP 为请求-响应式协议，指客户端先向服务器发送请求，然后服务器接收请求后，再向客户端发送响应信息。服务器向客户端发送的响应信息，包含三个部分: 状态行、消息报头和消息正文。状态行包括 HTTP 版本和状态码。消息报头包括浏览器、服务器或消息正文的相关信息。消息正文为返回的实体数据。
在以 Java 语言为服务的响应中，消息报头是存储在 Header 属性中的。主要实现方法有两种：HttpServletResponse.setHeader(name, MIME) 和 HttpServletResponse.addHeader(name, MIME)。下面详细介绍两种方法的底层实现原理及其区别。参考 Tomcat 源码版本8.5.31。

二、底层实现
三、setHeader 与 addHeader 的区别根据上面的分析可以看出，响应头的属性可以分为两种: 特殊属性与普通属性。其中，Content-type 与 Content-length 为特殊属性，MimeHeaderFields  中为普通属性。响应头的属性都在 coyote/Response 类中。
从底层实现原理看，setHeader 是通过新建或覆盖来实现属性配置的，而 addHeader 只会新增属性到队列中。此处需要说明，属性若已存在，setHeader 的进行覆盖后，还会将其他同名属性移除队列。源码实现:
// 属性组private MimeHeaderField[] headers = new MimeHeaderField[8];/** * Allow "set" operations, which removes all current values * for this header. * @param name The header name * @return the message bytes container for the value */public MessageBytes setValue(String name) &#123;    for(int i = 0; i &lt; this.count; ++i) &#123;        if (this.headers[i].getName().equalsIgnoreCase(name)) &#123;            for(int j = i + 1; j &lt; this.count; ++j) &#123;                if (this.headers[j].getName().equalsIgnoreCase(name)) &#123;                    this.removeHeader(j--);                &#125;            &#125;            return this.headers[i].getValue();        &#125;    &#125;    MimeHeaderField mh = this.createHeader();    mh.getName().setString(name);    return mh.getValue();&#125;
继续分析，addHeader 为属性设置多个值，那么我们可以获取哪个值呢？通过属性名查询属性的方法有 getHeader(name)，getHeaders(name)。实现方法如下:
/*** getHeader(name)* @param name 属性名* @return     属性*/public MessageBytes getValue(String name) &#123;    for (int i = 0; i &lt; count; i++) &#123;        if (headers[i].getName().equalsIgnoreCase(name)) &#123;            return headers[i].getValue();        &#125;    &#125;    return null;&#125;/*** getHeaders(name)* @param name 属性名* @return     该属性名对应的所有属性值*/public Collection&lt;String&gt; getHeaders(String name) &#123;    Enumeration&lt;String&gt; enumeration =            getCoyoteResponse().getMimeHeaders().values(name);    List&lt;String&gt; result = new ArrayList&lt;&gt;();    while (enumeration.hasMoreElements()) &#123;        result.add(enumeration.nextElement());    &#125;    return result;&#125;
从方法实现可以看出，getHeader 会返回匹配到的第一个属性值，而 getHeaders 则返回相同属性名的所有属性值。我们可以通过程序示例证实：
response.setHeader("set", "one");response.setHeader("set", "two");response.addHeader("add", "a");response.addHeader("add", "b");response.addHeader("add", "c");response.addHeader("add", "d");public static void main(String[] args) &#123;        String setName = "set";    String addName = "add";        log.info("setHeader -&gt; getHeader 方式查询到: &#123;&#125;", response.getHeader(setName));    log.info("setHeader -&gt; getHeaders 方式查询到: &#123;&#125;", response.getHeaders(setName));        log.info("addHeader -&gt; getHeader 方式查询到: &#123;&#125;", response.getHeader(addName));    log.info("addHeader -&gt; getHeaders 方式查询到: &#123;&#125;", response.getHeaders(addName));&#125;----- 输出setHeader -&gt; getHeader 方式查询到: twosetHeader -&gt; getHeaders 方式查询到: twoaddHeader -&gt; getHeader 方式查询到: aaddHeader -&gt; getHeaders 方式查询到: [a, b, c, d]

一、项目简介上一节介绍了 Spring Batch 的基础架构和设计原理，本节将通过一个简单的批处理任务来学习如何使用 Spring Batch。

现在需要将逗号分隔值文件 sample-data.cvs 中的数据，按照姓氏、名称拆分，导入数据表 person 中。看图可知，BatchProcessJob 只有一个 Step，分为三个部分：解析 cvs 文件；将文件数据转化为 Person 对象；将 Person 对象信息导入数据表 batch-demo.person。
二、项目搭建与配置
使用Spring 应用构建工具，即可创建项目。我的应用部署地址：spring-batch-demo
三、创建数据表Spring Batch 的组件JobRepository， 专门负责与数据库打交道，记录整个批处理中的增加、检索、更新、删除动作。也就是说，Spring Batch 是依赖数据库进行管理的。数据表创建脚本可在仓库中找到。MySQL 数据库的脚本文件为：schema-mysql.sql。框架依赖表建好后，不要忘了创建表 batch-demo.person。
USE batch-demo;CREATE TABLE `person` (  `person_id` bigint(30) unsigned NOT NULL AUTO_INCREMENT,  `first_name` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,  `last_name` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,  PRIMARY KEY (`person_id`)) ENGINE=InnoDB AUTO_INCREMENT=142 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='人员信息表';
四、批处理任务配置
根据批处理框架的运作流程，我们做出如下配置：
4.1 cvs文件内容读取器：
import com.example.springbatchdemo.entity.Person;import org.springframework.batch.item.file.FlatFileItemReader;import org.springframework.batch.item.file.builder.FlatFileItemReaderBuilder;import org.springframework.batch.item.file.mapping.BeanWrapperFieldSetMapper;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.core.io.ClassPathResource;@Configurationpublic class CustomItemReader &#123;    @Bean("personItemReader")    public FlatFileItemReader&lt;Person&gt; personItemReader() &#123;        return new FlatFileItemReaderBuilder&lt;Person&gt;()                .name("personItemReader")                .resource(new ClassPathResource("sample-data.csv"))                .delimited()                .names(new String[]&#123;"firstName", "lastName"&#125;)                .fieldSetMapper(new BeanWrapperFieldSetMapper&lt;Person&gt;() &#123;&#123;                    setTargetType(Person.class);                &#125;&#125;)                .build();    &#125;&#125;
4.2 解析数据处理器：
import com.example.springbatchdemo.entity.Person;import org.slf4j.Logger;import org.slf4j.LoggerFactory;import org.springframework.batch.item.ItemProcessor;import org.springframework.context.annotation.Configuration;@Configurationpublic class PersonItemProcessor implements ItemProcessor&lt;Person, Person&gt; &#123;    private static final Logger log = LoggerFactory.getLogger(PersonItemProcessor.class);    @Override    public Person process(final Person person) throws Exception &#123;        final String firstName = person.getFirstName();        final String lastName = person.getLastName();        final Person transformedPerson = new Person();        transformedPerson.setFirstName(firstName);        transformedPerson.setLastName(lastName);        log.info("Converting (&#123;&#125;) into (&#123;&#125;)", person, transformedPerson);        return transformedPerson;    &#125;&#125;
4.3 Person 对象写入器：
import com.example.springbatchdemo.entity.Person;import org.springframework.batch.item.database.BeanPropertyItemSqlParameterSourceProvider;import org.springframework.batch.item.database.JdbcBatchItemWriter;import org.springframework.batch.item.database.builder.JdbcBatchItemWriterBuilder;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Qualifier;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import javax.sql.DataSource;@Configurationpublic class CustomItemWriter &#123;    @Autowired    @Qualifier(value = "batchDemoDB")    private DataSource batchDemoDB;    @Bean("personItemWriter")    public JdbcBatchItemWriter&lt;Person&gt; personItemWriter() &#123;        return new JdbcBatchItemWriterBuilder&lt;Person&gt;()                .itemSqlParameterSourceProvider(new BeanPropertyItemSqlParameterSourceProvider&lt;&gt;())                .sql("INSERT INTO person (first_name, last_name) VALUES (:firstName, :lastName)")                .dataSource(batchDemoDB)                .build();    &#125;&#125;
4.4 MySQL 数据源配置：
import com.zaxxer.hikari.HikariDataSource;import org.springframework.boot.context.properties.ConfigurationProperties;import org.springframework.boot.jdbc.DataSourceBuilder;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.context.annotation.Primary;import javax.sql.DataSource;@Configurationpublic class DataSourceConfig &#123;    @Primary    @Bean(name = "batchDemoDB")    // 数据源配置参数识别前缀, 根据具体配置来设定    @ConfigurationProperties(prefix = "spring.datasource.batch-demo")    public DataSource druidDataSource() &#123;        // 使用 SpringBoot 默认的数据源 HikariDataSource        return DataSourceBuilder.create().type(HikariDataSource.class).build();    &#125;&#125;
4.5 Step 配置
import com.example.springbatchdemo.component.processor.PersonItemProcessor;import com.example.springbatchdemo.entity.Person;import org.springframework.batch.core.Step;import org.springframework.batch.core.configuration.annotation.StepBuilderFactory;import org.springframework.batch.item.database.JdbcBatchItemWriter;import org.springframework.batch.item.file.FlatFileItemReader;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Qualifier;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;import org.springframework.scheduling.concurrent.ThreadPoolTaskExecutor;@Configurationpublic class BatchProcessPersonStep &#123;    @Autowired    public StepBuilderFactory stepBuilderFactory;    @Autowired    @Qualifier(value = "personItemReader")    private FlatFileItemReader&lt;Person&gt; personItemReader;    @Autowired    @Qualifier(value = "personItemWriter")    private JdbcBatchItemWriter&lt;Person&gt; personItemWriter;    @Autowired    private PersonItemProcessor personItemProcessor;    @Bean("batchProcessPersonStep1")    public Step step1() &#123;        return stepBuilderFactory.get("step1")                .&lt;Person, Person&gt;chunk(10)                .reader(personItemReader)                .processor(personItemProcessor)                .writer(personItemWriter)                .build();    &#125;&#125;
4.6 Job 配置
import com.example.springbatchdemo.component.listener.BatchProcessPersonCompletionListener;import org.springframework.batch.core.Job;import org.springframework.batch.core.Step;import org.springframework.batch.core.configuration.annotation.EnableBatchProcessing;import org.springframework.batch.core.configuration.annotation.JobBuilderFactory;import org.springframework.batch.core.launch.support.RunIdIncrementer;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.beans.factory.annotation.Qualifier;import org.springframework.context.annotation.Bean;import org.springframework.context.annotation.Configuration;@Configuration@EnableBatchProcessingpublic class BatchProcessPersonJob &#123;    @Autowired    public JobBuilderFactory jobBuilderFactory;    @Autowired    @Qualifier(value = "batchProcessPersonStep1")    private Step batchProcessPersonStep1;    @Autowired    private BatchProcessPersonCompletionListener batchProcessPersonCompletionListener;    @Bean    public Job importUserJob() &#123;        return jobBuilderFactory.get("importUserJob")                .preventRestart()                .incrementer(new RunIdIncrementer())                .listener(batchProcessPersonCompletionListener)                .flow(batchProcessPersonStep1)                .end()                .build();    &#125;&#125;
4.7 任务状态监听器
import com.example.springbatchdemo.entity.Person;import com.example.springbatchdemo.mapper.PersonMapper;import org.slf4j.Logger;import org.slf4j.LoggerFactory;import org.springframework.batch.core.BatchStatus;import org.springframework.batch.core.JobExecution;import org.springframework.batch.core.listener.JobExecutionListenerSupport;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.stereotype.Component;import java.util.List;@Componentpublic class BatchProcessPersonCompletionListener extends JobExecutionListenerSupport &#123;    private static final Logger log = LoggerFactory.getLogger(BatchProcessPersonCompletionListener.class);    @Autowired    private PersonMapper personMapper;    @Override    public void afterJob(JobExecution jobExecution) &#123;        if (BatchStatus.COMPLETED.equals(jobExecution.getStatus())) &#123;            log.info("Job finished! Time to verify the results");            // spring-mybatis 查询所有的人员信息            List&lt;Person&gt; personList = personMapper.queryAll();            personList.forEach(person -&gt; log.info("Found &lt;&#123;&#125;&gt; in the database.", person));        &#125;    &#125;&#125;
