/** * Job */@Beanpublic Job testDatabaseItemReaderJob() &#123;    return jobBuilderFactory.get("testDatabaseItemReaderJob")        .incrementer(new RunIdIncrementer())        .flow(testDatabaseItemReaderStep)        .end()        .build();&#125;/** * Step */@Bean("testDatabaseItemReaderStep")public Step testDatabaseItemReaderStep(PlatformTransactionManager transactionManager) &#123;    return stepBuilderFactory.get("testDatabaseItemReaderStep")        .transactionManager(transactionManager)        .&lt;Student, Student&gt;chunk(10)        .reader(studentItemReader)        .writer(list -&gt; list.forEach(System.out::println))        .build();&#125;/** * Reader */@Bean("studentItemReader")public JdbcPagingItemReader&lt;Student&gt; studentItemReader() &#123;    MySqlPagingQueryProvider queryProvider = new MySqlPagingQueryProvider();    queryProvider.setSelectClause("student_id, name, address");    queryProvider.setFromClause("from student_source");    Map&lt;String, Order&gt; sortKeys = new HashMap&lt;&gt;(1);    sortKeys.put("student_id", Order.ASCENDING);    queryProvider.setSortKeys(sortKeys);    return new JdbcPagingItemReaderBuilder&lt;Student&gt;()        .name("studentItemReader")        .dataSource(batchDemoDB)        .fetchSize(1000)        .rowMapper(new StudentRowMapper())        .queryProvider(queryProvider)        .build();&#125;public class StudentRowMapper implements RowMapper&lt;Student&gt; &#123;        /**     * Student 字段映射     */    @Override    public Student mapRow(ResultSet rs, int rowNum) throws SQLException &#123;        Student student = new Student();        student.setStudentId(rs.getLong("student_id"));        student.setName(rs.getString("name"));        student.setAddress(rs.getString("address"));        return student;    &#125;&#125;/** * MySQL 数据源配置 */@Primary@Bean(name = "batchDemoDB")@ConfigurationProperties(prefix = "spring.datasource.batch-demo")public DataSource druidDataSource() &#123;    return DataSourceBuilder.create().type(HikariDataSource.class).build();&#125;
